// ──────────────────────────────────────────────
// Format the Slack message
// ──────────────────────────────────────────────

const data = $('Filter Valid Clients').item.json;
const analysis = $json.message?.content || $json.response?.text || $json.text || 'Great engagement this week!';

const views = Number(data.views || 0).toLocaleString('en-US');
const likes = Number(data.likes || 0).toLocaleString('en-US');
const comments = Number(data.comments || 0).toLocaleString('en-US');
const shares = Number(data.shares || 0).toLocaleString('en-US');
const platform = (data.platform || 'instagram').charAt(0).toUpperCase() + (data.platform || 'instagram').slice(1);
const videoUrl = data.video_url || '';

const blocks = [
  {
    type: 'header',
    text: {
      type: 'plain_text',
      text: `\u{1F525} Top Reel of the Week`,
      emoji: true
    }
  },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `Hey *${data.client_name}* team! Here's your top-performing reel this week:`
    }
  },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*Platform:*\n${platform}` },
      { type: 'mrkdwn', text: `*Views:*\n${views}` },
      { type: 'mrkdwn', text: `*Likes:*\n${likes}` },
      { type: 'mrkdwn', text: `*Comments:*\n${comments}` },
      { type: 'mrkdwn', text: `*Shares:*\n${shares}` }
    ]
  },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*Caption:*\n>${data.caption ? data.caption.substring(0, 200) : 'N/A'}`
    }
  },
  {
    type: 'divider'
  },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*Why it performed well:*\n${analysis}`
    }
  }
];

// Add video link button if available
if (videoUrl && videoUrl !== '#') {
  blocks.push({
    type: 'actions',
    elements: [
      {
        type: 'button',
        text: {
          type: 'plain_text',
          text: `\u{25B6}\u{FE0F} Watch Reel`,
          emoji: true
        },
        url: videoUrl,
        action_id: 'watch_reel'
      }
    ]
  });
}

return {
  json: {
    slack_channel_id: data.slack_channel_id,
    client_name: data.client_name,
    text: `Top reel of the week for ${data.client_name}: ${views} views`,
    blocks: JSON.stringify(blocks)
  }
};
